class Solution:
    def rotateString(self, s, goal):
        if len(s) != len(goal):
            return False
        n = len(s)
        for k in range(n):
            if s[k:] + s[:k] == goal:
                return True
        return False

solutions.python:
class Solution:
    def rotateString(self, s, goal):
        return len(s) == len(goal) and goal in (s + s)

